import pytest
import requests

BASE_URL = "http://banking-api"

@pytest.fixture()
def unique_user_token():
    return <generate_unique_user_token>()

@pytest.fixture(autouse=True)
def reset_rate_limit(unique_user_token):
    <reset_rate_limit>(unique_user_token)
    yield

def test_60th_request_succeeds_and_61st_is_rejected(unique_user_token, reset_rate_limit):
    headers = {"Authorization": f"Bearer {unique_user_token}"}
    for i in range(1, 61):
        r = requests.get(f"{BASE_URL}/health", headers=headers, timeout=5)
        assert r.status_code == 200, f"Request {i} failed with {r.status_code}"
    overage = requests.get(f"{BASE_URL}/health", headers=headers, timeout=5)
    assert overage.status_code == 429, f"Expected 429, got {overage.status_code}"
    retry_after = overage.headers.get("Retry-After")
    assert retry_after is not None, "Retry-After header missing"
    assert int(retry_after) > 0, f"Retry-After must be positive, got {retry_after}"

import pytest
import requests

BASE_URL = "http://banking-api"

@pytest.fixture()
def unique_user_token():
    return <generate_unique_user_token>()

@pytest.fixture(autouse=True)
def reset_rate_limit(unique_user_token):
    <reset_rate_limit>(unique_user_token)
    yield

def test_burst_above_limit_returns_429_with_retry_after(unique_user_token, reset_rate_limit):
    headers = {"Authorization": f"Bearer {unique_user_token}"}
    responses = [
        requests.get(f"{BASE_URL}/health", headers=headers, timeout=5)
        for _ in range(80)
    ]
    statuses = [r.status_code for r in responses]
    rejected = [r for r in responses if r.status_code == 429]
    assert len(rejected) >= 20, f"Expected >=20 rejections, got {len(rejected)}"
    for r in rejected:
        retry_after = r.headers.get("Retry-After")
        assert retry_after is not None, "Retry-After header missing on 429"
        assert int(retry_after) > 0, f"Invalid Retry-After: {retry_after}"
    first_429_idx = next(i for i, s in enumerate(statuses) if s == 429)
    assert first_429_idx >= 60, f"429 appeared too early at index {first_429_idx}"
